String ModernMediaControlResource::getValue(const String &resource_key) {
     HashMap<String, String>::iterator it = imageMapBase64.find(resource_key);
     return it != imageMapBase64.end() ? it->value : "Key not found"_s;
}

const HashMap<String, String>& ModernMediaControlResource::getImageMap() const {
    return imageMap;
}
